const fs = require('fs');
const path = require('path');

const input = $json || {};
const placeholder = 'REEMPLAZAR_TELEGRAM_BOT_TOKEN_EN_N8N';
const defaultWorkflowVersion = 'CFDI_WITH_HISTORY_3C2_ROUTER_FIX';
const expectedCatalogPath = 'C:/Users/Juandi Gamer/Documents/Flujo N8N CFDI/data/concepts.normalized.json';
const expectedRuntimePath = 'C:/Users/Juandi Gamer/Documents/Flujo N8N CFDI/runtime';
const stateFileName = 'telegram-state.json';

function ensureAbsolutePath(rawPath, label, expected) {
  const value = (rawPath || '').toString().trim();
  if (!value) throw new Error(label + ' es requerido. Usa: ' + expected);
  if (!path.isAbsolute(value)) throw new Error(label + ' debe ser absoluto. Usa: ' + expected);
  return path.normalize(value);
}

function defaultState(workflowVersion) {
  return {
    lastTelegramUpdateId: 0,
    processedUpdateIds: [],
    chatStates: {},
    lastRunAt: '',
    workflowVersion: workflowVersion || defaultWorkflowVersion,
  };
}

function normalizeState(raw, workflowVersion) {
  const base = defaultState(workflowVersion);
  const state = raw && typeof raw === 'object' ? raw : {};
  const processed = Array.isArray(state.processedUpdateIds) ? state.processedUpdateIds : [];
  return {
    ...base,
    ...state,
    lastTelegramUpdateId: Number(state.lastTelegramUpdateId || 0) || 0,
    processedUpdateIds: processed.map((id) => Number(id)).filter((id) => Number.isFinite(id)).slice(-500),
    chatStates: state.chatStates && typeof state.chatStates === 'object' ? state.chatStates : {},
    workflowVersion: workflowVersion || state.workflowVersion || base.workflowVersion,
  };
}

function readState(statePath, workflowVersion) {
  if (!fs.existsSync(statePath)) return defaultState(workflowVersion);
  try {
    return normalizeState(JSON.parse(fs.readFileSync(statePath, 'utf8')), workflowVersion);
  } catch (_error) {
    return defaultState(workflowVersion);
  }
}

function writeState(statePath, state) {
  fs.writeFileSync(statePath, JSON.stringify(state, null, 2), 'utf8');
}

const workflowVersion = (input.workflowVersion || defaultWorkflowVersion).toString().trim();
const telegramBotToken = (input.telegramBotToken || '').toString().trim();
const catalogPath = ensureAbsolutePath(input.catalogPath, 'catalogPath', expectedCatalogPath);
const runtimePath = ensureAbsolutePath(input.runtimePath, 'runtimePath', expectedRuntimePath);
const pollingLimit = Number(input.pollingLimit || 10) || 10;

if (!telegramBotToken || telegramBotToken === placeholder) {
  throw new Error('Configura telegramBotToken en el nodo Set Config. No pegues el token en archivos del proyecto.');
}

fs.mkdirSync(runtimePath, { recursive: true });
const statePath = path.join(runtimePath, stateFileName);
const state = readState(statePath, workflowVersion);
state.workflowVersion = workflowVersion;
state.lastRunAt = new Date().toISOString();
writeState(statePath, state);

const lastUpdateId = Number(state.lastTelegramUpdateId || 0) || 0;
const nextOffset = lastUpdateId > 0 ? lastUpdateId + 1 : 0;

return [{
  json: {
    ...input,
    workflowVersion,
    telegramBotToken,
    catalogPath,
    runtimePath,
    statePath,
    pollingLimit,
    lastUpdateId,
    lastTelegramUpdateId: lastUpdateId,
    processedUpdateIdsCount: state.processedUpdateIds.length,
    nextOffset,
    offsetStrategy: 'runtime_file_state',
