const fs = require('fs');
const path = require('path');

const config = $node['Prepare Telegram Request'] ? $node['Prepare Telegram Request'].json : {};
const response = $json || {};
const updates = Array.isArray(response.result) ? response.result : [];
const defaultWorkflowVersion = 'CFDI_WITH_HISTORY_3C2_ROUTER_FIX';
const stateFileName = 'telegram-state.json';
const files = {
  events: 'telegram-events.jsonl',
  drafts: 'cfdi-drafts.jsonl',
  actions: 'actions-log.jsonl',
};

function defaultState(workflowVersion) {
  return {
    lastTelegramUpdateId: 0,
    processedUpdateIds: [],
    chatStates: {},
    lastRunAt: '',
    workflowVersion: workflowVersion || defaultWorkflowVersion,
  };
}

function normalizeState(raw, workflowVersion) {
  const base = defaultState(workflowVersion);
  const state = raw && typeof raw === 'object' ? raw : {};
  const processed = Array.isArray(state.processedUpdateIds) ? state.processedUpdateIds : [];
  return {
    ...base,
    ...state,
    lastTelegramUpdateId: Number(state.lastTelegramUpdateId || 0) || 0,
    processedUpdateIds: processed.map((id) => Number(id)).filter((id) => Number.isFinite(id)).slice(-500),
    chatStates: state.chatStates && typeof state.chatStates === 'object' ? state.chatStates : {},
    workflowVersion: workflowVersion || state.workflowVersion || base.workflowVersion,
  };
}

function readState(statePath, workflowVersion) {
  if (!fs.existsSync(statePath)) return defaultState(workflowVersion);
  try {
    return normalizeState(JSON.parse(fs.readFileSync(statePath, 'utf8')), workflowVersion);
  } catch (_error) {
    return defaultState(workflowVersion);
  }
}

function writeState(statePath, state) {
  fs.writeFileSync(statePath, JSON.stringify(state, null, 2), 'utf8');
}

function appendJsonl(filePath, value) {
  fs.appendFileSync(filePath, JSON.stringify(value) + '\n', 'utf8');
}

function actionId(timestamp, suffix) {
  return 'ACT-' + timestamp.replace(/[-:.TZ]/g, '') + '-' + String(suffix || 'polling');
}

const workflowVersion = config.workflowVersion || defaultWorkflowVersion;
const runtimePath = path.normalize(config.runtimePath || '');
const statePath = config.statePath ? path.normalize(config.statePath) : path.join(runtimePath, stateFileName);
const eventsPath = path.join(runtimePath, files.events);
const draftsPath = path.join(runtimePath, files.drafts);
const actionsPath = path.join(runtimePath, files.actions);
fs.mkdirSync(runtimePath, { recursive: true });
[eventsPath, draftsPath, actionsPath].forEach((filePath) => {
  if (!fs.existsSync(filePath)) fs.appendFileSync(filePath, '', 'utf8');
});

const state = readState(statePath, workflowVersion);
const lastUpdateId = Number(state.lastTelegramUpdateId || config.lastTelegramUpdateId || 0) || 0;
const processed = new Set((state.processedUpdateIds || []).map((id) => String(id)));
const now = new Date().toISOString();

if (updates.length === 0) {
  state.lastRunAt = now;
  state.workflowVersion = workflowVersion;
  writeState(statePath, state);
  return [];
}

const validUpdates = [];
let maxValidUpdateId = lastUpdateId;

updates
  .slice()
  .sort((a, b) => Number(a.update_id || 0) - Number(b.update_id || 0))
  .forEach((update) => {
    const updateId = Number(update.update_id);
    if (!Number.isFinite(updateId)) return;
    if (updateId <= lastUpdateId) return;
    if (processed.has(String(updateId))) return;

    const message = update.message || {};
    const text = typeof message.text === 'string' ? message.text.trim() : '';
    const chatId = message.chat && message.chat.id !== undefined ? message.chat.id : null;
    if (!text || chatId === null) return;

    maxValidUpdateId = Math.max(maxValidUpdateId, updateId);
    validUpdates.push({ update, updateId, message, text, chatId });
  });

if (validUpdates.length === 0) {
  state.lastRunAt = now;
  state.workflowVersion = workflowVersion;
  writeState(statePath, state);
  return [];
}

for (const item of validUpdates) {
  processed.add(String(item.updateId));
}
state.processedUpdateIds = Array.from(processed).map((id) => Number(id)).filter((id) => Number.isFinite(id)).slice(-500);
state.lastTelegramUpdateId = maxValidUpdateId;
state.lastRunAt = now;
state.workflowVersion = workflowVersion;
writeState(statePath, state);

appendJsonl(actionsPath, {
  action_id: actionId(now, maxValidUpdateId),
  timestamp: now,
  command: 'TELEGRAM_UPDATE_PRECOMMITTED',
  update_ids: validUpdates.map((item) => item.updateId),
  lastTelegramUpdateId: state.lastTelegramUpdateId,
  processedUpdateIdsCount: state.processedUpdateIds.length,
  workflowVersion,
});

return validUpdates.map((item) => ({
  json: {
    workflowVersion,
    telegramBotToken: config.telegramBotToken,
    catalogPath: config.catalogPath,
    runtimePath,
    statePath,
    eventsPath,
    draftsPath,
    actionsPath,
    pollingLimit: config.pollingLimit,
    lastUpdateId,
    lastTelegramUpdateId: state.lastTelegramUpdateId,
    processedUpdateIdsCount: state.processedUpdateIds.length,
    update_id: item.updateId,
    message_id: item.message.message_id || null,
    chat_id: item.chatId,
    text: item.text,
    message: item.text,
    date: item.message.date || null,
    nextOffset: state.lastTelegramUpdateId + 1,
    offsetStrategy: 'runtime_file_state_precommitted',
    update_precommitted: true,
  },
}));

const fs = require('fs');
const path = require('path');

const DEFAULT_CATALOG = { concepts: [] };

const WORD_TOKEN_RE = /[a-z0-9]+/g;

const FAMILY_HINTS = {
