  const command = parsed.command;
  const arg = parsed.arg;
  const drafts = latestDrafts(paths.draftsPath);
  const timestamp = new Date().toISOString();

  if (command === '/start' || command === '/help') {
    return commandResult('COMMAND_HELP', commandHelp(), { command, route: 'help', workflowVersion });
  }

  if (command === '/debug') {
    return commandResult('COMMAND_DEBUG', buildDebugMessage(paths), { command, route: 'debug', workflowVersion });
  }

  if (command === '/cancelar') {
    const existed = clearChatState(paths, input.chat_id);
    const text = existed ? 'Aclaracion pendiente cancelada.' : 'No habia aclaracion pendiente para cancelar.';
    return commandResult('COMMAND_CANCELAR', text, { command, route: 'cancelar', cleared: existed });
  }

  if (command === '/pendientes') {
    const pending = drafts.filter((draft) => draft.status === 'PENDIENTE').slice(0, 10);
    const text = pending.length
      ? ['Pendientes:', ...pending.map(draftSummaryLine)].join('\n')
      : 'No hay borradores pendientes.';
    return commandResult('COMMAND_PENDIENTES', text, { command, route: 'pendientes' });
  }

  if (command === '/aprobadas') {
    const approved = drafts.filter((draft) => draft.status === 'APROBADO').slice(0, 10);
    const text = approved.length
      ? ['Aprobadas:', ...approved.map(draftSummaryLine)].join('\n')
      : 'No hay borradores aprobados.';
    return commandResult('COMMAND_APROBADAS', text, { command, route: 'aprobadas' });
  }

  if (command === '/hoy') {
    const today = todayKey(timestamp);
    const todayDrafts = drafts.filter((draft) => todayKey(draft.timestamp) === today);
    const events = readJsonl(paths.eventsPath).filter((event) => todayKey(event.timestamp) === today);
    const count = (status) => todayDrafts.filter((draft) => draft.status === status).length;
    const blocked = events.filter((event) => ['BLOQUEAR', 'AGREGAR_ACTIVIDAD'].includes(event.result_action)).length;
    const text = [
      'Resumen de hoy ' + today,
      'Pendientes: ' + count('PENDIENTE'),
      'Aprobados: ' + count('APROBADO'),
      'Descartados: ' + count('DESCARTADO'),
      'Bloqueados: ' + blocked,
    ].join('\n');
    return commandResult('COMMAND_HOY', text, { command, route: 'hoy' });
  }

  if (command === '/aprobar') {
    const text = arg ? updateDraftStatus(paths, arg, 'APROBADO', input.chat_id).text : 'Uso: /aprobar DRAFT_ID';
    return commandResult('COMMAND_APROBAR', text, { command, draft_id: arg || null, route: 'aprobar' });
  }

  if (command === '/descartar') {
    const text = arg ? updateDraftStatus(paths, arg, 'DESCARTADO', input.chat_id).text : 'Uso: /descartar DRAFT_ID';
    return commandResult('COMMAND_DESCARTAR', text, { command, draft_id: arg || null, route: 'descartar' });
  }

  if (command === '/detalle') {
    const draft = drafts.find((item) => String(item.draft_id) === String(arg));
    const text = arg ? draftDetail(draft) : 'Uso: /detalle DRAFT_ID';
    return commandResult('COMMAND_DETALLE', text, { command, draft_id: arg || null, route: 'detalle' });
  }

  return commandResult(
    'COMMAND_UNKNOWN',
    ['Comando no reconocido.', commandHelp()].join('\n\n'),
    { command, route: 'unknown' },
  );
}

function appendEvent(paths, result) {
  const timestamp = new Date().toISOString();
  appendJsonl(paths.eventsPath, {
    event_id: eventIdFromTimestamp(timestamp, input.update_id),
    timestamp,
    update_id: input.update_id || '',
    message_id: input.message_id || '',
    chat_id: input.chat_id || '',
    text: message,
    result_action: result.action || result.accion_n8n || '',
    ready_to_copy: result.ready_to_copy === true,
    telegram_message: result.telegram_message || '',
    workflowVersion,
  });
}

function appendDraftIfNeeded(paths, result) {
  if (!(result.action === 'SUGERIR' && result.ready_to_copy === true)) return null;
  const existing = readJsonl(paths.draftsPath).some((draft) => String(draft.update_id || '') === String(input.update_id || ''));
  if (existing) return null;

  const timestamp = new Date().toISOString();
  const draft = {
    draft_id: draftIdFromTimestamp(timestamp, input.update_id),
    timestamp,
    update_id: input.update_id || null,
    message_id: input.message_id || null,
    chat_id: input.chat_id || '',
    message_original: result.message_original || message,
    status: 'PENDIENTE',
    action: result.action,
    ready_to_copy: result.ready_to_copy === true,
    concept: result.concept || emptyConcept(),
    top_3: Array.isArray(result.top_3) ? result.top_3 : [],
    requires_human_review: true,
  };
  appendJsonl(paths.draftsPath, draft);
  appendJsonl(paths.actionsPath, {
    action_id: 'ACT-' + timestamp.replace(/[-:.TZ]/g, '') + '-' + String(input.update_id || 'manual'),
    timestamp,
    chat_id: input.chat_id || '',
    update_id: input.update_id || null,
    message_id: input.message_id || null,
    command: 'CREATE_DRAFT',
    draft_id: draft.draft_id,
    status_after: 'PENDIENTE',
  });
  return draft;
}

let response;
let runtimePaths = null;
try {
  if (!message) throw new Error('Mensaje vacio: no hay texto para procesar.');
  runtimePaths = ensureRuntime(runtimePath);

  if (message.startsWith('/')) {
    response = handleCommand(runtimePaths);
  } else if (shouldAskToSeparateMessages(message)) {
    response = appendWorkflowVersion(buildSeparateMessagesResponse(message));
  } else {
    const resolvedCatalogPath = ensureCatalogInputPath(catalogPath);
    if (!fs.existsSync(resolvedCatalogPath)) {
      throw new Error('Archivo no encontrado: ' + resolvedCatalogPath + '. Revisa catalogPath y confirma que exista concepts.normalized.json.');
    }
    const catalog = JSON.parse(fs.readFileSync(resolvedCatalogPath, 'utf8'));
    const previousChatState = getChatState(runtimePaths, input.chat_id);
    const hasPendingClarification = Boolean(previousChatState && previousChatState.original_text);
    const scoringMessage = hasPendingClarification
      ? [String(previousChatState.original_text || '').trim(), message].filter(Boolean).join(' ')
      : message;
    const raw = classifyMessage(scoringMessage, catalog);
    response = buildN8nResponse(raw, scoringMessage);
    response.json_debug = {
      ...(response.json_debug || {}),
      used_chat_state: hasPendingClarification,
      current_message: message,
      previous_original_text: hasPendingClarification ? previousChatState.original_text : null,
    };
    if (response.action === 'PEDIR_ACLARACION') {
      saveChatState(runtimePaths, input.chat_id, {
        status: 'PEDIR_ACLARACION',
        original_text: scoringMessage,
        last_text: message,
        update_id: input.update_id || null,
        message_id: input.message_id || null,
      });
    } else {
      clearChatState(runtimePaths, input.chat_id);
    }
    const createdDraft = appendDraftIfNeeded(runtimePaths, response);
    if (createdDraft) {
      response.telegram_message = response.telegram_message + '\n\nBorrador pendiente: ' + createdDraft.draft_id;
      response.json_debug = { ...(response.json_debug || {}), draft_id: createdDraft.draft_id };
    }
    response = appendWorkflowVersion(response);
  }

  appendEvent(runtimePaths, response);
} catch (error) {
  response = makeErrorResponse(error);
  try {
    runtimePaths = ensureRuntime(runtimePath || 'C:/Users/Juandi Gamer/Documents/Flujo N8N CFDI/runtime');
    appendEvent(runtimePaths, response);
  } catch (_ignored) {}
}

return [{
  json: {
    ...input,
    ...response,
    telegramBotToken: input.telegramBotToken,
    chat_id: input.chat_id,
    update_id: input.update_id,
    message_id: input.message_id,
    text: input.text,
    workflowVersion,
    statePath: runtimePaths ? runtimePaths.statePath : input.statePath,
    eventsPath: runtimePaths ? runtimePaths.eventsPath : input.eventsPath,
    draftsPath: runtimePaths ? runtimePaths.draftsPath : input.draftsPath,
    actionsPath: runtimePaths ? runtimePaths.actionsPath : input.actionsPath,
    send_text: response.telegram_message,
  },
}];

const fs = require('fs');
const path = require('path');

function appendJsonl(filePath, value) {
  fs.appendFileSync(filePath, JSON.stringify(value) + '\n', 'utf8');
}

function compactError(value) {
  if (!value) return '';
  if (typeof value === 'string') return value;
  if (value.message) return String(value.message);
  if (value.description) return String(value.description);
  try { return JSON.stringify(value); } catch (_error) { return String(value); }
}

const current = $json || {};
let source = {};
try {
  if (typeof $items === 'function') {
    const prior = $items('Handle Commands And Scoring', 0, $itemIndex) || [];
    if (prior[0] && prior[0].json) source = prior[0].json;
  }
} catch (_error) {}

const runtimePath = path.normalize(source.runtimePath || current.runtimePath || '');
const actionsPath = source.actionsPath || current.actionsPath || (runtimePath ? path.join(runtimePath, 'actions-log.jsonl') : '');
const timestamp = new Date().toISOString();
const statusCode = Number(current.statusCode || current.status || 0) || 0;
const failed = Boolean(
  current.error ||
  current.errorMessage ||
  current.message === 'The connection to the server was closed unexpectedly' ||
  statusCode >= 400 ||
  current.ok === false ||
  (current.description && current.ok !== true)
);

if (actionsPath) {
  try {
    fs.mkdirSync(path.dirname(actionsPath), { recursive: true });
    appendJsonl(actionsPath, {
      action_id: 'ACT-' + timestamp.replace(/[-:.TZ]/g, '') + '-' + String(source.update_id || current.update_id || 'send'),
      timestamp,
      command: failed ? 'SEND_MESSAGE_FAILED' : 'SEND_MESSAGE_OK',
      update_id: source.update_id || current.update_id || null,
      message_id: source.message_id || current.message_id || null,
      chat_id: source.chat_id || current.chat_id || null,
      workflowVersion: source.workflowVersion || current.workflowVersion || '',
      error: failed ? compactError(current.error || current.errorMessage || current.description || current.message || current) : null,
    });
  } catch (_ignored) {}
}

return [{
  json: {
    ...source,
    send_result: current,
    send_failed: failed,
  },
}];
